// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class PackedMaskLayoutTest {

	@Test
	void selectsOneTwoAndMultiWordLayoutsAtBoundaries() {
		assertEquals(PackedMaskLayout.Kind.ONE_WORD, PackedMaskLayout.forSymbols(0).kind());
		assertEquals(PackedMaskLayout.Kind.ONE_WORD, PackedMaskLayout.forSymbols(64).kind());
		assertEquals(PackedMaskLayout.Kind.TWO_WORD, PackedMaskLayout.forSymbols(65).kind());
		assertEquals(PackedMaskLayout.Kind.TWO_WORD, PackedMaskLayout.forSymbols(128).kind());
		assertEquals(PackedMaskLayout.Kind.MULTI_WORD, PackedMaskLayout.forSymbols(129).kind());
		assertEquals(3, PackedMaskLayout.forSymbols(129).wordCount());
	}

	@Test
	void performsSetAlgebraInsideSharedWordArena() {
		PackedMaskLayout layout = PackedMaskLayout.forSymbols(130);
		long[] arena = new long[layout.wordCount() * 3];
		int left = 0;
		int right = layout.wordCount();
		int union = right + layout.wordCount();

		layout.set(arena, left, 0);
		layout.set(arena, left, 64);
		layout.set(arena, right, 64);
		layout.set(arena, right, 129);

		assertTrue(layout.intersects(arena, left, arena, right));
		assertFalse(layout.containsAll(arena, left, arena, right));

		layout.union(arena, union, arena, left, arena, right);
		assertTrue(layout.contains(arena, union, 0));
		assertTrue(layout.contains(arena, union, 64));
		assertTrue(layout.contains(arena, union, 129));
		assertEquals(3, layout.cardinality(arena, union));
	}
}
